create extension if not exists pgcrypto;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, username text unique, display_name text, avatar_url text, language text not null default 'ar', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.user_interests (user_id uuid references public.profiles(id) on delete cascade, interest text not null, created_at timestamptz default now(), primary key(user_id, interest));
create table if not exists public.media_items (id uuid primary key default gen_random_uuid(), source text not null, source_id text not null, media_type text not null check (media_type in ('movie','tv','game')), title text not null, poster_url text, overview text, release_date date, metadata jsonb not null default '{}', unique(source, source_id, media_type));
create table if not exists public.user_lists (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.profiles(id) on delete cascade, name text not null, list_type text not null default 'custom', created_at timestamptz default now());
create table if not exists public.list_items (id uuid primary key default gen_random_uuid(), list_id uuid not null references public.user_lists(id) on delete cascade, media_item_id uuid not null references public.media_items(id) on delete cascade, status text not null default 'planned', progress int not null default 0, created_at timestamptz default now(), unique(list_id, media_item_id));
create table if not exists public.ratings (user_id uuid references public.profiles(id) on delete cascade, media_item_id uuid references public.media_items(id) on delete cascade, rating numeric(2,1) check (rating >= 0 and rating <= 5), created_at timestamptz default now(), primary key(user_id, media_item_id));
create table if not exists public.news_items (id uuid primary key default gen_random_uuid(), source_id text unique, title text not null, description text, url text not null, image_url text, published_at timestamptz not null, category text, created_at timestamptz default now());
create table if not exists public.saved_news (user_id uuid references public.profiles(id) on delete cascade, news_id uuid references public.news_items(id) on delete cascade, created_at timestamptz default now(), primary key(user_id, news_id));
create table if not exists public.posts (id uuid primary key default gen_random_uuid(), author_id uuid references public.profiles(id) on delete cascade, body text not null, image_url text, media_item_id uuid references public.media_items(id), created_at timestamptz default now());
create table if not exists public.comments (id uuid primary key default gen_random_uuid(), post_id uuid references public.posts(id) on delete cascade, author_id uuid references public.profiles(id) on delete cascade, body text not null, created_at timestamptz default now());
create table if not exists public.post_reactions (post_id uuid references public.posts(id) on delete cascade, user_id uuid references public.profiles(id) on delete cascade, reaction text not null default 'like', created_at timestamptz default now(), primary key(post_id, user_id));
create table if not exists public.follows (follower_id uuid references public.profiles(id) on delete cascade, following_id uuid references public.profiles(id) on delete cascade, created_at timestamptz default now(), primary key(follower_id, following_id), check (follower_id <> following_id));
create table if not exists public.blocks (blocker_id uuid references public.profiles(id) on delete cascade, blocked_id uuid references public.profiles(id) on delete cascade, created_at timestamptz default now(), primary key(blocker_id, blocked_id));
create table if not exists public.reports (id uuid primary key default gen_random_uuid(), reporter_id uuid references public.profiles(id) on delete set null, target_type text not null, target_id uuid not null, reason text not null, created_at timestamptz default now());
create index if not exists media_items_type_title_idx on public.media_items(media_type, title);
create index if not exists posts_created_at_idx on public.posts(created_at desc);
alter table public.profiles enable row level security; alter table public.user_interests enable row level security; alter table public.media_items enable row level security; alter table public.user_lists enable row level security; alter table public.list_items enable row level security; alter table public.ratings enable row level security; alter table public.news_items enable row level security; alter table public.saved_news enable row level security; alter table public.posts enable row level security; alter table public.comments enable row level security; alter table public.post_reactions enable row level security; alter table public.follows enable row level security; alter table public.blocks enable row level security; alter table public.reports enable row level security;
create policy "public read profiles" on public.profiles for select using (true);
create policy "own profile write" on public.profiles for all using (auth.uid() = id) with check (auth.uid() = id);
create policy "public read media" on public.media_items for select using (true);
create policy "public read news" on public.news_items for select using (published_at >= now() - interval '90 days');
create policy "authenticated community read" on public.posts for select using (true);
create policy "own posts write" on public.posts for all using (auth.uid() = author_id) with check (auth.uid() = author_id);
